// Extract conversation data from the Intercom webhook payload
// and determine if this conversation should be escalated

const payload = $input.first().json;
const data = payload.data?.item || payload;

// --- Extract conversation metadata ---
const conversationId = data.id || 'unknown';
const createdAt = data.created_at ? new Date(data.created_at * 1000) : new Date();
const source = data.source || {};
const contact = data.contacts?.contacts?.[0] || {};
const tags = data.tags?.tags?.map(t => t.name.toLowerCase()) || [];

// --- Customer info ---
const customerName = contact.name || source.author?.name || 'Unknown Customer';
const customerEmail = contact.email || source.author?.email || '';
const companyName = contact.companies?.companies?.[0]?.name || 'Unknown Company';

// --- Conversation content ---
const conversationParts = data.conversation_parts?.conversation_parts || [];
const allMessages = [source.body || '', ...conversationParts.map(p => p.body || '')]
  .filter(Boolean);
const lastMessageExcerpt = allMessages[allMessages.length - 1]?.substring(0, 500) || 'No message content';
const fullConversationText = allMessages.join('\n\n').substring(0, 3000);

// --- Priority tags (customize these to match your Intercom tags) ---
const ESCALATION_TAGS = ['urgent', 'vip', 'escalation', 'p1', 'critical', 'at-risk', 'churn-risk'];
const VIP_TAGS = ['vip', 'enterprise', 'key-account'];

const hasPriorityTag = tags.some(t => ESCALATION_TAGS.includes(t));
const isVip = tags.some(t => VIP_TAGS.includes(t));

// --- SLA check: flag if conversation is > 2 hours old with no assignee ---
const ageMinutes = (Date.now() - createdAt.getTime()) / (1000 * 60);
const isUnassigned = !data.assignee || !data.assignee.id;
const isSlaBreaching = ageMinutes > 120 && isUnassigned;

// --- Escalation decision ---
const isEscalation = hasPriorityTag || isVip || isSlaBreaching;

// --- Priority label ---
let priorityLabel = '🟡 Normal';
if (isVip && hasPriorityTag) priorityLabel = '🔴 P1 — VIP + Priority Tag';
else if (isVip) priorityLabel = '🟠 VIP Customer';
else if (hasPriorityTag) priorityLabel = '🔴 Priority Tag Detected';
else if (isSlaBreaching) priorityLabel = '🟠 SLA Risk (2h unassigned)';

const conversationLink = `https://app.intercom.com/a/apps/YOUR_APP_ID/conversations/${conversationId}`;

return [{
  json: {
    conversationId,
    customerName,
    customerEmail,
    companyName,
    tags,
    hasPriorityTag,
    isVip,
    isSlaBreaching,
    isEscalation,
    priorityLabel,
    ageMinutes: Math.round(ageMinutes),
    lastMessageExcerpt,
    fullConversationText,
    conversationLink
  }
}];

