// Merge OpenAI summary back with the original conversation data
const openAiResponse = $input.first().json;
const summary = openAiResponse.text || openAiResponse.choices?.[0]?.text || 'Summary unavailable';

// Get the original data from two steps back
const originalData = $('Is Escalation?').first().json;

return [{
  json: {
    ...originalData,
    aiSummary: summary.trim()
  }
}];
